var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아버지께서... 그런 짓을 할 리 없어.","JPN":"お父様が……そんなことをするはずがない。","ENG":"My father... would never do something like that.","TWN":"父親不可能做出那種事。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"전부...!","JPN":"全部……！","ENG":"It must all...!","TWN":"這一切……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그자의 탓일 테니까...!","JPN":"全部あの者のせいなのだから……！","ENG":"Be that person's fault...!","TWN":"一定都是那傢伙的錯……！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"대체 당신에게 누가 무슨 짓을 저지른 거야?","JPN":"いったいあなたに誰が、何をしたの？","ENG":"What exactly did someone do to you?","TWN":"到底是誰對你做了什麼？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"누구보다 그 녀석을 막으려 했던 당신이... 왜 그렇게 변한 거냐고.","JPN":"誰よりもあいつを止めようとしていたあなたが……どうしてそんな風になっちゃったんだよ。","ENG":"You of all people, who tried harder than anyone to stop that person... why did you change like that?","TWN":"比起任何人都更想阻止那傢伙的你……為什麼變成這樣了？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"제 마음은, 한 번도 변한 적 없사옵니다.","JPN":"わたくしの心は、一度も変わっておりません。","ENG":"My heart has never changed, not even once.","TWN":"我的心，未曾改變。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저는... 어제와 같은 오늘이 좋사옵니다.","JPN":"わたくしは……昨日と同じ今日が良いのでございます。","ENG":"I... prefer a today that is the same as yesterday.","TWN":"我……喜歡像昨天一樣的今天。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저의 과거가 타인에 대한 증오를 품는다면, 오늘 역시 과거의 증오에 물들여 질 테지요. ","JPN":"過去のわたくしが他人に対して憎悪を抱いていたら、今日のわたくしもまた過去の憎悪に染まるでしょう。 ","ENG":"If my past harbors hatred toward others, then today too will be stained by that hatred of the past.","TWN":"如果我的過去對他人抱有仇恨，那麼今天也會被過去的仇恨染上色彩。 "},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그런 끝없는 굴레에 갇히는 걸... 저는 원치 않나이다.","JPN":"そのような繰り返される運命に縛られることを……わたくしは望んでおりません。","ENG":"To be trapped in such an endless cycle... that is something I do not desire.","TWN":"我並不希望……被困在那樣無止盡的循環裡。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...증오...","JPN":"……憎悪……","ENG":"...Hatred...","TWN":"……仇恨……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"나도... 다르지 않구나.","JPN":"自分も……同じだったんだ。","ENG":"I'm no different... am I?","TWN":"我也……一樣。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"다른 세계를 멸망시켜서... 그걸 양분으로 삼았다고?","JPN":"他の世界を滅亡させて……それを養分にしてるだって？","ENG":"You're saying another world was destroyed... and used as nourishment?","TWN":"毀滅其他世界……再把那一切當作養分？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"예.","JPN":"はい。","ENG":"Yes.","TWN":"對。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그것이 제가 알게 된... 황금나무와 낙원의 진실이옵니다.","JPN":"これがわたくしが知り得た……黄金の木と楽園の真実でございます。","ENG":"That is the truth I came to learn... about the Golden Tree and the Promised Land.","TWN":"那正是我知道的……黃金樹與樂園的真相。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래서 넌 그 책임을 묻기 위해 아우드라를 만나려 했지만...","JPN":"それで、君はその責任を問うためにアウドラに会おうとしたけど……","ENG":"So you tried to meet Audra to hold her accountable...","TWN":"所以你原本打算去見奧德拉，向她追問這件事的責任……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"도중에 생각을 바꿔 날 찾아왔다는 거지?","JPN":"途中で気が変わって私のところに来たんだ。","ENG":"But you changed your mind along the way and came to see me instead?","TWN":"但途中改變想法、轉而來找我，是這樣嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...그렇사옵니다.","JPN":"……そうでございます。","ENG":"...That is correct.","TWN":"……就是這樣。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"고마워. 날 믿기로 해줘서.","JPN":"ありがとう。私のことを信じてくれて。","ENG":"Thank you. For choosing to trust me.","TWN":"謝謝你，願意選擇相信我。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"전... 누군가를 믿으려는 게 아니옵니다.","JPN":"わたくしは……誰かを信じようとしているわけではございません。","ENG":"I... am not trying to trust someone.","TWN":"我……並不是想要相信誰。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저 스스로를 믿지 못하게 됐을 뿐.","JPN":"自分自身を信じられなくなっただけです。","ENG":"I simply came to a point where I could no longer trust myself.","TWN":"我只是連我自己都已經無法再相信了。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그런 건 나도 마찬가지야.","JPN":"そんなの、私も同じだよ。","ENG":"I'm the same way.","TWN":"這一點我也一樣。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"스스로를 믿을 순 없기 때문에, 다른 사람을 찾는 거지.","JPN":"自分自身を信用できないこそ、他の人に頼る。","ENG":"Because we can't trust ourselves, we end up looking for someone else.","TWN":"正因為無法相信自己，才會尋找別人。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내면의 목소리라는 건 결국... 옳고 그름 앞에서 나 자신을 변호할 수 밖에 없으니까.","JPN":"内面の声というものは結局……良し悪しの前では自分自身を弁護してしまうものだからね。","ENG":"After all, the voice inside our heads can only end up defending ourselves when faced with right and wrong.","TWN":"所謂內心的聲音，到最後……在直面對與錯時，也只會替自己辯護罷了。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그러니 에클레시아도 날 도와줘.","JPN":"だから、エクレシアも私を助けて。","ENG":"So help me too, Ecclesia.","TWN":"所以艾可露西亞，也請你幫幫我。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내가 잘못된 길에 들어서 일을 그르치지 않도록.","JPN":"私が間違った道を選んで、失敗しないように。","ENG":"So that I don't lose my way and make a mistake.","TWN":"別讓我走上錯誤的道路，把事情搞砸。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...이제, 어쩌할 계획이시옵니까?","JPN":"……これから、どうするおつもりですか？","ENG":"...What do you plan to do now?","TWN":"……那麼，你接下來打算怎麼做？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아침이 돌아오기 전, 아우드라는 분명 눈을 떴어.","JPN":"朝が来る前、アウドラは確かに目を覚ました。","ENG":"Before morning returned, Audra surely woke up.","TWN":"在早晨到來前，奧德拉應該已經醒了。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그녀가 살아있다는 걸 확인했으니 만나러 가야지.","JPN":"彼女が生きてることを確認したから、会いに行く。","ENG":"Now that we know she's alive, we should go meet her.","TWN":"既然已經確認她還活著，就去見她吧。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그렇다면, 무기를 챙겨가는 게 좋겠사옵니다.","JPN":"なら、武器を用意された方が良いでしょう。","ENG":"In that case, it would be wise to bring weapons.","TWN":"這樣的話，最好還是帶上武器。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"무기? 싸우려고?","JPN":"武器？　戦う気？","ENG":"Weapons? You're expecting a fight?","TWN":"武器？要戰鬥嗎？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};